out vec4 fragColor;
uniform float uTime;
uniform float uScale;
uniform vec3 uColorA;
uniform vec3 uColorB;
void main(){
  vec2 uv = (vUV.st - 0.5) * 2.0 * max(uScale, 0.0001);
  float v = sin(uv.x * 6.0 + uTime)
          + sin(uv.y * 6.0 + uTime * 1.3)
          + sin((uv.x + uv.y) * 4.0 + uTime * 0.7)
          + sin(length(uv) * 8.0 - uTime * 1.7);
  float t = 0.5 + 0.25 * v;
  vec3 col = mix(uColorA, uColorB, clamp(t, 0.0, 1.0));
  fragColor = TDOutputSwizzle(vec4(col, 1.0));
}
